const src = $('image').first().json;
const vf = $json || {};

// 1) Lay text OCR tu cac truong pho bien
const baseText =
  (typeof vf.ocr_text === 'string' && vf.ocr_text.trim()) ||
  (typeof vf.raw_text === 'string' && vf.raw_text.trim()) ||
  (typeof vf.text === 'string' && vf.text.trim()) ||
  '';

// 2) Gom line items neu co
let itemsText = '';
if (Array.isArray(vf.line_items) && vf.line_items.length) {
  itemsText = vf.line_items
    .map((it, idx) => {
      const desc = it.description || it.text || 'Muc khong ro';
      const qty = it.quantity ?? '';
      const amount = it.total ?? it.price ?? '';
      return `${idx + 1}. ${desc} | SL: ${qty} | Tien: ${amount}`;
    })
    .join('\n');
}

// 3) Tao ocrText tong hop
const ocrText = [baseText, itemsText].filter(Boolean).join('\n').trim();
const ocrStatus = ocrText ? 'ok' : 'empty';

// 4) Lay metadata hoa don neu co
const vendor =
  (vf.vendor && (vf.vendor.name || vf.vendor)) ||
  vf.vendor_name ||
  '';
const date = vf.date || vf.invoice_date || '';
const total = vf.total ?? vf.grand_total ?? '';

// 5) Dong goi lai chatInput cho Agent (bat buoc la string)
const agentInput = [
  `Cau hoi nguoi dung: ${src.chatInput || ''}`,
  `Da gui anh: Co`,
  `OCR status: ${ocrStatus}`,
  `Vendor: ${vendor}`,
  `Date: ${date}`,
  `Total: ${total}`,
  '',
  'Noi dung OCR:',
  ocrText || 'Khong trich xuat duoc noi dung ro rang.'
].join('\n');

return [
  {
    json: {
      action: src.action || '',
      sessionId: src.sessionId || '',
      hasImage: true,
      ocrStatus,
      ocrText,
      vendor,
      date,
      total,
      chatInput: agentInput
    }
  }
];

const candidate = $json.output ?? $json.text ?? $json.response ?? $json;
let data = {};

if (typeof candidate === "string") {
const raw = candidate;
const start = raw.indexOf("{");
const end = raw.lastIndexOf("}") + 1;

if (start >= 0 && end > start) {
try {
data = JSON.parse(raw.slice(start, end));
} catch (e) {
data = {};
}
}
} else if (candidate && typeof candidate === "object") {
data = candidate;
} else if ($json && typeof $json === "object") {
data = $json;
}

const amount = data.amount != null ? Number(data.amount) : null;
const vendor = data.vendor ?? null;
const transacted_at = data.transacted_at ?? data.date ?? null;
const suggested_category = data.suggested_category ?? null;
const note = data.note ?? (vendor ? "Hoa don " + vendor : null);

return [
{
json: {
amount,
vendor,
transacted_at,
suggested_category,
note,
line_items: data.line_items ?? [],
confidence: data.confidence ?? null,
needs_review: data.needs_review ?? true,
warnings: data.warnings ?? [],
},
},
];

const src = $json.body ?? $json;

console.log("Input keys:", Object.keys(src));
console.log("Image object:", src.image);

const imageObj = src.image ?? null;

if (!imageObj) {
  throw new Error(`Image not found. Structure: ${JSON.stringify(src).substring(0, 300)}`);
}

const rawData = String(imageObj.data ?? "").trim();

if (!rawData) {
  throw new Error(`Image data is empty`);
}

const base64 = rawData.replace(/^data:[^;]+;base64,/, "");

return [
  {
    json: {
      image: {
        name: imageObj.name ?? "upload.jpg",
        mimeType: imageObj.mimeType ?? "image/jpeg",
        data: base64,
      },
      user_id: src.user_id ?? "",
    },
  },
];
